export const UserService = {
  async getUser(id: string): Promise<any> {
    const user = await db.users.findUnique({ where: { id } });
    return user;
  },
  async getUserWithPosts(id: string): Promise<any> {
    const user = await db.users.findUnique({ where: { id }, include: { posts: true } });
    return user;
  },
  async getUserWithPostsAndComments(id: string): Promise<any> {
    const user = await db.users.findUnique({ where: { id }, include: { posts: { include: { comments: true } } } });
    return user;
  }
};
